// Parsea el IRN por SIEFORE generacional (SISET cd=212) y arma filas para afore_irn.
// Toma el ULTIMO valor de cada fila (la columna más reciente).
const GENS=[['sb de pensiones','SB de Pensiones'],['sb 60-64','SB 60-64'],['sb 65-69','SB 65-69'],
 ['sb 70-74','SB 70-74'],['sb 75-79','SB 75-79'],['sb 80-84','SB 80-84'],['sb 85-89','SB 85-89'],
 ['sb 90-94','SB 90-94'],['sb 95-99','SB 95-99'],['sb inicial','SB Inicial']];
const AF=[['azteca','Azteca'],['banamex','Citibanamex'],['coppel','Coppel'],['inbursa','Inbursa'],
 ['invercap','Invercap'],['pensionissste','PensionISSSTE'],['principal','Principal'],
 ['profuturo','Profuturo'],['sura','SURA'],['xxi-banorte','Banorte']];

const html=$('IRN cd=212').first().json.data;
const text=String(html||'').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').toLowerCase();

// periodo = último "mes año" antes de la primera AFORE
const firstAz=text.indexOf('azteca');
const head=firstAz>0?text.slice(0,firstAz):text;
const meses=head.match(/(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\s+\d{4}/g)||[];
const periodo=meses.length?meses[meses.length-1]:null;

// posiciones de cada generación
const gpos=GENS.map(([k,lbl])=>({k,lbl,i:text.indexOf('neto '+k)})).filter(o=>o.i>=0).sort((a,b)=>a.i-b.i);
const rows=[];
gpos.forEach((g,gi)=>{
  const gend = gi+1<gpos.length ? gpos[gi+1].i : text.length;
  const sec=text.slice(g.i,gend);
  // posiciones de cada AFORE dentro de la sección
  const apos=AF.map(([k,afore])=>({k,afore,i:sec.indexOf(k)})).filter(o=>o.i>=0).sort((a,b)=>a.i-b.i);
  apos.forEach((a,ai)=>{
    const aend = ai+1<apos.length ? apos[ai+1].i : sec.length;
    const slice=sec.slice(a.i+a.k.length, aend);
    const nums=(slice.match(/\d+\.\d+/g)||[]).map(Number);
    if(nums.length){ rows.push({ afore:a.afore, generacion:g.lbl, irn:nums[nums.length-1], periodo }); }
  });
});
return [{ json: { rows, _debug:{ periodo, generaciones:gpos.length, filas:rows.length, ejemplo:rows[0] } } }];
